def isValidSerialization(preorder: str) -> bool:
    # Every node consumes 1 slot and non-null nodes produce 2 slots.
    # Start with 1 slot (for root). If slots < 0 at any point → invalid.
    slots = 1
    for node in preorder.split(','):
        slots -= 1
        if slots < 0:
            return False
        if node != '#':
            slots += 2
    return slots == 0
